import{_ as i,o as l,c as t,ae as e}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"初探 RAG 架构：为什么企业知识问答通常先做检索增强","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/rag-intro.md","filePath":"ai-tutorial/rag-intro.md"}'),s={name:"ai-tutorial/rag-intro.md"};function r(n,a,o,h,p,u){return l(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="初探-rag-架构-为什么企业知识问答通常先做检索增强" tabindex="-1">初探 RAG 架构：为什么企业知识问答通常先做检索增强 <a class="header-anchor" href="#初探-rag-架构-为什么企业知识问答通常先做检索增强" aria-label="Permalink to &quot;初探 RAG 架构：为什么企业知识问答通常先做检索增强&quot;">​</a></h1><blockquote><p>只要一提“让模型懂公司知识”，微调几乎总会第一个跳出来。它听起来像个很顺手的答案：既然模型不懂，那就把知识喂进去嘛。 但真实业务里，事情通常没这么直给。多数企业知识不是一句“学会了”就算完，它们会更新、会分权限、会有出处要求，还经常和具体的业务上下文绑在一起。也正因为这样，RAG 才会成为更常见的起点。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>为什么企业知识场景通常优先考虑 RAG</li><li>微调和 RAG 分别解决什么问题</li><li>一个基础 RAG 系统包含哪些核心环节</li><li>什么场景适合 RAG，什么场景不适合</li></ul></div><h2 id="_1-先回答一个核心问题-你想补的是-知识-还是-能力" tabindex="-1">1. 先回答一个核心问题：你想补的是“知识”还是“能力” <a class="header-anchor" href="#_1-先回答一个核心问题-你想补的是-知识-还是-能力" aria-label="Permalink to &quot;1. 先回答一个核心问题：你想补的是“知识”还是“能力”&quot;">​</a></h2><p>微调和 RAG 经常被拿来对比，但它们解决的问题并不完全一样。</p><h3 id="_1-1-微调更像在调整能力或风格" tabindex="-1">1.1 微调更像在调整能力或风格 <a class="header-anchor" href="#_1-1-微调更像在调整能力或风格" aria-label="Permalink to &quot;1.1 微调更像在调整能力或风格&quot;">​</a></h3><p>微调更适合：</p><ul><li>固定输出格式</li><li>专项任务风格</li><li>行业语气和表达</li><li>特定任务习惯</li></ul><h3 id="_1-2-rag-更像在补充事实来源" tabindex="-1">1.2 RAG 更像在补充事实来源 <a class="header-anchor" href="#_1-2-rag-更像在补充事实来源" aria-label="Permalink to &quot;1.2 RAG 更像在补充事实来源&quot;">​</a></h3><p>RAG 更适合：</p><ul><li>企业制度</li><li>合同文档</li><li>产品说明</li><li>FAQ</li><li>经常更新的知识材料</li></ul><p>如果你真正缺的是“最新事实”，RAG 往往比微调更自然。</p><h2 id="_2-为什么企业知识更适合放在外部知识层" tabindex="-1">2. 为什么企业知识更适合放在外部知识层 <a class="header-anchor" href="#_2-为什么企业知识更适合放在外部知识层" aria-label="Permalink to &quot;2. 为什么企业知识更适合放在外部知识层&quot;">​</a></h2><p>企业知识通常具有几个特点：</p><ul><li>更新频繁</li><li>权限复杂</li><li>来源分散</li><li>需要保留出处</li></ul><p>这些特征和参数化存储并不天然匹配。因为一旦事实变化，你并不能像更新数据库那样精确改掉模型里的旧知识。</p><p>而 RAG 的思路是：</p><ul><li>让模型继续负责理解和表达</li><li>让外部系统负责提供事实</li></ul><p>这样更接近现代软件系统的职责分工。</p><h2 id="_3-一个基础-rag-系统长什么样" tabindex="-1">3. 一个基础 RAG 系统长什么样 <a class="header-anchor" href="#_3-一个基础-rag-系统长什么样" aria-label="Permalink to &quot;3. 一个基础 RAG 系统长什么样&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D[&quot;原始文档&quot;] --&gt; P[&quot;清洗与切块&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; E[&quot;Embedding 向量化&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; V[&quot;索引 / 向量库&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;用户问题&quot;] --&gt; QE[&quot;问题向量化&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    QE --&gt; R[&quot;相似度召回&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V --&gt; R</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; C[&quot;组装上下文&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; L[&quot;模型生成答案&quot;]</span></span></code></pre></div><p>你可以把它理解成三段：</p><ol><li><strong>入库</strong>：文档被清洗、切块、建立索引</li><li><strong>召回</strong>：问题到来时，从候选知识中找相关片段</li><li><strong>生成</strong>：把片段作为事实依据，辅助模型作答</li></ol><h2 id="_4-rag-的价值不只是-知道答案-还有可控性" tabindex="-1">4. RAG 的价值不只是“知道答案”，还有可控性 <a class="header-anchor" href="#_4-rag-的价值不只是-知道答案-还有可控性" aria-label="Permalink to &quot;4. RAG 的价值不只是“知道答案”，还有可控性&quot;">​</a></h2><p>在工程实践中，RAG 的价值不仅体现在回答质量，还体现在系统治理上：</p><ul><li>可以按权限控制不同知识源</li><li>可以展示引用出处</li><li>可以单独更新文档，不必重训模型</li><li>可以分层定位问题：是检索错了，还是生成错了</li></ul><p>这些特性对企业场景尤其重要。</p><h2 id="_5-什么时候不要把-rag-当万能解法" tabindex="-1">5. 什么时候不要把 RAG 当万能解法 <a class="header-anchor" href="#_5-什么时候不要把-rag-当万能解法" aria-label="Permalink to &quot;5. 什么时候不要把 RAG 当万能解法&quot;">​</a></h2><p>RAG 也有边界，不是所有问题都适合。</p><h3 id="_5-1-不适合的场景" tabindex="-1">5.1 不适合的场景 <a class="header-anchor" href="#_5-1-不适合的场景" aria-label="Permalink to &quot;5.1 不适合的场景&quot;">​</a></h3><ul><li>需要严格实时写操作</li><li>需要复杂事务执行</li><li>任务重点不在知识，而在操作或规划</li><li>问题主要依赖数据库中的结构化实时数据</li></ul><p>这时更合适的可能是：</p><ul><li>工具调用</li><li>工作流系统</li><li>数据库查询层</li></ul><h3 id="_5-2-rag-不等于-检索完就一定答对" tabindex="-1">5.2 RAG 不等于“检索完就一定答对” <a class="header-anchor" href="#_5-2-rag-不等于-检索完就一定答对" aria-label="Permalink to &quot;5.2 RAG 不等于“检索完就一定答对”&quot;">​</a></h3><p>即使引入 RAG，也仍然可能失败：</p><ul><li>文档切块不合理</li><li>召回不到关键证据</li><li>候选结果噪声太大</li><li>上下文组装不佳</li></ul><p>这也是为什么 RAG 后续会继续演化出混合检索、重排和上下文压缩等能力。</p><h2 id="_6-一个更实用的判断标准" tabindex="-1">6. 一个更实用的判断标准 <a class="header-anchor" href="#_6-一个更实用的判断标准" aria-label="Permalink to &quot;6. 一个更实用的判断标准&quot;">​</a></h2><p>如果你在做企业知识问答，可以先问：</p><ol><li>知识是否主要来自文档或说明材料？</li><li>知识是否更新频繁？</li><li>是否需要保留引用来源？</li><li>是否存在细粒度权限控制？</li></ol><p>如果答案大多为是，那么 RAG 往往是更自然的起点。</p><h2 id="_7-小结" tabindex="-1">7. 小结 <a class="header-anchor" href="#_7-小结" aria-label="Permalink to &quot;7. 小结&quot;">​</a></h2><p>RAG 的意义，不只是“让模型查资料”，而是把知识管理从模型参数里拆出来，交给一个更适合存储、检索和治理事实的外部系统。</p><p>它并不能解决所有 AI 问题，但在企业知识问答场景里，通常是比“先微调”更稳、更快、更可控的起点。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a></li><li><a href="https://cookbook.openai.com/" target="_blank" rel="noreferrer">OpenAI Cookbook</a></li><li>延伸阅读：<a href="./rag-deep-dive.html">深入剖析 RAG</a></li></ul>`,46)])])}const k=i(s,[["render",r]]);export{c as __pageData,k as default};
